import { useState } from "react";
import { searchPatientByPhone, getPatientHistory } from "../api";

export default function Search() {
  const [phone, setPhone] = useState("");
  const [history, setHistory] = useState(null);
  const [loading, setLoading] = useState(false);

  const search = async () => {
    if (!phone) return alert("Enter phone number");

    try {
      setLoading(true);

      const patient = await searchPatientByPhone(phone);

      if (!patient) {
        alert("Patient not found");
        setHistory(null);
        return;
      }

      const data = await getPatientHistory(patient.id);
      setHistory(data);

    } catch (err) {
      alert(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Patient History</h2>

      <input
        placeholder="Phone number"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
      />

      <button onClick={search} disabled={loading}>
        Search
      </button>

      {!history ? (
        <p>No data</p>
      ) : (
        <>
          <h3>👤 Patient</h3>
          <p>{history.patient.name}</p>
          <p>{history.patient.phone}</p>
          <p>{history.patient.age}</p>

          <hr />

          <h3>📅 Appointments</h3>
          {history.appointments.map(a => (
            <div key={a.id}>
              {new Date(a.date).toLocaleString()}
            </div>
          ))}

          <hr />

          <h3>💊 Prescriptions</h3>
          {history.prescriptions.map(p => (
            <div key={p.id}>
              <b>{p.medicines}</b> - {p.notes}
            </div>
          ))}
        </>
      )}
    </div>
  );
}
